/* empty css              */function i(){const n=document.getElementById("mobile-menu-button"),e=document.getElementById("mobile-menu");!n||!e||(n.addEventListener("click",()=>{e.style.maxHeight!=="0px"&&e.style.maxHeight!==""?(e.style.maxHeight="0",e.style.opacity="0"):(e.style.maxHeight="500px",e.style.opacity="1")}),e.querySelectorAll("a").forEach(t=>{t.addEventListener("click",()=>{e.style.maxHeight="0",e.style.opacity="0"})}))}function c(){document.querySelectorAll('a[href^="#"]').forEach(n=>{n.addEventListener("click",function(e){const t=this.getAttribute("href");if(t==="#")return;e.preventDefault();const o=document.querySelector(t);o&&o.scrollIntoView({behavior:"smooth",block:"start"})})})}document.addEventListener("DOMContentLoaded",()=>{i(),c()});
